#import "ChatMessageCell.h"
#import "PrefixHeader.h"

@implementation ChatMessageCell

- (instancetype)initWithStyle:(UITableViewCellStyle)style reuseIdentifier:(NSString *)identifier {
    self = [super initWithStyle:style reuseIdentifier:identifier];
    if (self) {
        [self setupSubviews];
        // 隐藏单元格底部的分割线
        self.backgroundColor=CLEAR_COLOR;
        self.separatorInset = UIEdgeInsetsMake(0, CGRectGetMaxX(self.contentView.frame) + 1000, 0, 0);
        // 设置被选中时背景不发生变化
        self.selectionStyle = UITableViewCellSelectionStyleNone;
        self.messageLabel.userInteractionEnabled = YES;
        UILongPressGestureRecognizer *longPressGesture = [[UILongPressGestureRecognizer alloc] initWithTarget:self action:@selector(handleLongPress:)];
        [self.messageLabel addGestureRecognizer:longPressGesture];
    }
    return self;
}

- (void)handleLongPress:(UILongPressGestureRecognizer *)gestureRecognizer {
    if (gestureRecognizer.state == UIGestureRecognizerStateBegan) {
        [self setSelected:NO animated:NO];
        // 获取长按的位置
        CGPoint location = [gestureRecognizer locationInView:self.messageLabel];
        if(self.type==MessageTypeSent){
            self.bubbleView.backgroundColor = BUTTON_COLOR;

        }else{
            self.bubbleView.backgroundColor = WHITE_COLOR;
        }
        [self.messageLabel becomeFirstResponder];
        [self showMenuAtLocation:location];
    }
}

- (void)showMenuAtLocation:(CGPoint)location{
    UIMenuController *menuController = [UIMenuController sharedMenuController];
    UIMenuItem *copyItem = [[UIMenuItem alloc] initWithTitle:@"Copy" action:@selector(copyText:)];
    menuController.menuItems = @[copyItem];
    // 获取相对于 messageLabel 的目标矩形
    CGRect targetRect = CGRectMake(location.x, location.y, 1, 1);
    //targetRect = [self.messageLabel.superview convertRect:targetRect toView:nil];
    // 显示菜单
    [menuController showMenuFromView:self.messageLabel rect:targetRect];
}

- (void)copyText:(id)sender {
    UIPasteboard *pasteboard = [UIPasteboard generalPasteboard];
    pasteboard.string = self.messageLabel.text;
    // 显示成功的弹窗
    [UIView showHUDWithStatus:NSLocalizedString(@"Copy Successful", nil) imageName:@"Success"];
    if(self.type==MessageTypeSent){
        self.bubbleView.backgroundColor = BUTTON_COLOR;
    }else{
        self.bubbleView.backgroundColor = WHITE_COLOR;
    }
}

- (void)setSelected:(BOOL)selected animated:(BOOL)animated {
    // 不调用父类方法，避免选中状态
}

#pragma mark - Setup Subviews

- (void)setupSubviews {
    // 初始化各组件
    _avatarImageView = [[UIImageView alloc] init];
    _messageLabel = [[UILabel alloc] init];
    _timeLabel = [[UILabel alloc] init];
    _bubbleView = [[UIView alloc] init];
    _avatarImageView.contentMode = UIViewContentModeScaleAspectFill;
    // 设置气泡布局
    [_bubbleView.layer setCornerRadius:ZOOM(12)];
    _bubbleView.layer.masksToBounds = YES;
    // 设置消息标签样式
    _messageLabel.numberOfLines = 0;
    _messageLabel.lineBreakMode = NSLineBreakByWordWrapping; // 换行模式：单词换行
    _messageLabel.textAlignment = NSTextAlignmentLeft;
    _messageLabel.font=[UIFont systemFontOfSize:16.0];
    // 设置时间戳样式
    _timeLabel.hidden = NO;
    // 将子视图添加到cell的内容视图中
    [self.contentView addSubview:_avatarImageView];
    [self.contentView addSubview:_bubbleView];
    [self.contentView addSubview:_messageLabel];
    [self.contentView addSubview:_timeLabel];
    // 消息标签约束
    [_messageLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.bubbleView).offset(ZOOM(10));
        make.left.equalTo(self.bubbleView).offset(ZOOMW(10));
        make.right.equalTo(self.bubbleView).offset(-ZOOMW(10));
        //make.bottom.lessThanOrEqualTo(self.bubbleView).offset(-ZOOM(10));
    }];
}

#pragma mark - Prepare for Reuse

// 当单元格被复用时，清除旧的数据，确保每次展示都是最新的内容
- (void)prepareForReuse {
    [super prepareForReuse];
    // 清除旧数据
