+ (NSMutableDictionary<NSString *, NSMutableArray<MessageModel *> *> *)_messagesByAccountId {
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        _messagesByAccountId = [[NSMutableDictionary alloc] init];
    });
    return _messagesByAccountId;
}


+ (NSMutableArray<MessageModel *> *)messagesForAccount:(NSInteger)accountId{
    NSString *accountID = [NSString stringWithFormat:@"%ld", (long)accountId];
    NSMutableDictionary<NSString *, NSMutableArray<MessageModel *> *> *messagesDict = [self _messagesByAccountId];
    NSMutableArray<MessageModel *> *messages = messagesDict[accountID];
    if (!messages) {
        NSString *filePath = [self filePathForAccount:accountId];
        messages = [NSArray arrayWithJsonFile:filePath elementClass:[MessageModel class]].mutableCopy;
        messagesDict[accountID] = messages;
    }
    return messages;
}
+ (void)saveMessagesForAccount:(NSInteger)accountId {
    NSString *filePath = [self filePathForAccount:accountId];
    [[self messagesForAccount:accountId] writeToJsonFile:filePath];
}
+(void)saveMessageNum:(NSInteger)messagenum{
    // 1. 创建字典，将 NSInteger 包装为 JSON 格式
       NSDictionary *jsonDict = @{@"messageNum": @(messagenum)}; // 使用 NSNumber 包装 NSInteger
    NSLog(@"字典为：%@", jsonDict);
    // 2. 获取文件路径
        NSString *fileName = @"messagenum.json";
        NSArray *paths = NSSearchPathForDirectoriesInDomains(NSDocumentDirectory, NSUserDomainMask, YES);
        NSString *documentsDirectory = [paths firstObject];
        NSString *filePath = [documentsDirectory stringByAppendingPathComponent:fileName];
    // 3. 将字典转换为 JSON 数据
        NSError *error = nil;
        NSData *jsonData = [NSJSONSerialization dataWithJSONObject:jsonDict options:NSJSONWritingPrettyPrinted error:&error];
        if (error) {
            NSLog(@"Error converting dictionary to JSON: %@", error.localizedDescription);
            return;
        }
    // 4. 将 JSON 数据写入文件
        BOOL success = [jsonData writeToFile:filePath atomically:YES];
        if (success) {
            NSLog(@"Successfully saved JSON to file at path: %@", filePath);
        } else {
            NSLog(@"Failed to save JSON to file.");

        }
}
+ (NSInteger)getMessageNum{
    // 假设 JSON 文件路径为 "messagenum.json"
    NSString *fileName = @"messagenum.json";
    NSArray *paths = NSSearchPathForDirectoriesInDomains(NSDocumentDirectory, NSUserDomainMask, YES);
    NSString *documentsDirectory = [paths firstObject];
    NSString *filePath = [documentsDirectory stringByAppendingPathComponent:fileName];
        // 检查文件是否存在
        if (!filePath) {
            NSLog(@"Error: JSON file not found.");
            return 0; // 返回默认值 0
        }
        // 读取文件内容
        NSError *error = nil;
        NSString *fileContent = [NSString stringWithContentsOfFile:filePath encoding:NSUTF8StringEncoding error:&error];
        if (error) {
            NSLog(@"Error reading JSON file: %@", error.localizedDescription);
            return 0; // 返回默认值 0
        }
        // 将 JSON 字符串转换为字典
        NSData *jsonData = [fileContent dataUsingEncoding:NSUTF8StringEncoding];
        NSDictionary *dicMessageNum = [NSJSONSerialization JSONObjectWithData:jsonData options:kNilOptions error:&error];
        if (error) {
            NSLog(@"Error parsing JSON: %@", error.localizedDescription);
            return 0; // 返回默认值 0
        }

        // 获取 messageNum 的值
        NSInteger num = [dicMessageNum[@"messageNum"] integerValue];

        return num;
}

+ (void)setMessages:(NSMutableDictionary<NSString *, NSMutableArray<MessageModel *> *> *)messages {
    _messagesByAccountId = [messages mutableCopy];
}
+ (NSString *)filePathForAccount:(NSInteger)accountId {
    return [NSFileManager documentFilePathWithName:[NSString stringWithFormat:@"%ld_%@", (long)accountId, MESSAGES_FILE_PATH]];
}
+ (void)deleteMessagesFileForAccount:(NSInteger)accountId {
    NSString *filePath = [self filePathForAccount:accountId];
    NSFileManager *fileManager = [NSFileManager defaultManager];
