    if (success) {
        //NSLog(@"文件删除成功: %@", filePath);
    } else {
        NSLog(@"删除文件失败: %@", [error localizedDescription]);
    }
    // 清除缓存的消息数据
    NSString *accountID = [NSString stringWithFormat:@"%ld", (long)accountId];
    [_messagesByAccountId removeObjectForKey:accountID];
}
