- (void)editClick:(UIGestureRecognizer *)gestureRecognizer {
    // 获取点击的手势所在的单元格
    HomeTalkTableCell *cell = (HomeTalkTableCell *)gestureRecognizer.view;
    // 获取cell的indexPath
    NSIndexPath *indexPath = [self indexPathForCell:cell];
    if (indexPath != nil) {
        // 根据 indexPath 来执行不同的操作
        [self accountBeginEditing:indexPath];
    }
}
- (void)accountBeginEditing:(NSIndexPath *)indexPath {
    // 拿到正在编辑的帐号所在的行数

    AccountModel *account = [_accounts objectAtIndex:indexPath.row];
    dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.1 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
        // 通知控制器push编辑账户时的视图
        [(HomeViewController *)self.viewController showAiTalkVCWithAccount:account with:indexPath];
    });
}
//修改最近聊天
- (void)accountTipWordsModify:(NSIndexPath *)indexPath withNewTipWords:(NSString *)recentChat {
    if (indexPath.row == -1 && indexPath.section == -1) {
        return;  // 错误返回
    }
    AccountModel *modifyAccount = _accounts[indexPath.row];    // 拿到修改最近聊天对应的帐号
    if (!modifyAccount) {
        //NSLog(@"Account not found for the given indexPath.");
        return;     // 如果账号不存在，返回
    }
    modifyAccount.recentChat = recentChat;    // 更新账户的最近聊天信息
    [AccountModel save];    // 保存新的账户数据
    // 通知自己更新对应账户的行
    [self reloadRowAtIndexPath:indexPath withRowAnimation:UITableViewRowAnimationAutomatic];
    // 发个广播，通知home界面更新ui
    [NSNotificationCenter.defaultCenter postNotificationName:KeePassAccountChangedNotificationName object:nil];
    [self reloadData];
}
- (void)accountAppNameModify:(NSIndexPath *)indexPath withNewName:(NSString *)newName {
    if (indexPath.row == -1 && indexPath.section == -1) {
        // 无效路径，忽略或提示错误
        NSLog(@"Invalid index path provided.");
        return;
    }
    AccountModel *modifyAccount = _accounts[indexPath.row];    // 拿到修改名字行号对应的帐号
    if (!modifyAccount) {
        //NSLog(@"Account not found for the given indexPath.");
        return;
    }
    modifyAccount.aiName = newName;    // 更新账户的应用名称
    [AccountModel save];    // 保存新的账户数据
    // 通知自己更新对应账户的行
    [self reloadRowAtIndexPath:indexPath withRowAnimation:UITableViewRowAnimationAutomatic];
    // 发个广播，通知home界面更新ui
    [NSNotificationCenter.defaultCenter postNotificationName:KeePassAccountChangedNotificationName object:nil];
    [self reloadData];
}
- (void)accountShouldDelete:(NSIndexPath *)indexPath {
    AccountModel *deleteAccount = _accounts[indexPath.row];
    if (!deleteAccount || indexPath.row >= _accounts.count){
        // 无效路径，忽略或提示错误
        NSLog(@"Invalid index path provided.");
        return;
    }
    // 删除文件
    NSInteger aiID = deleteAccount.ID;
    [MessageModel deleteMessagesFileForAccount:aiID];
    // 将帐号从数组中删除
    [self.accounts removeObject:deleteAccount];
    [AccountModel.accounts removeObject:deleteAccount];
    // 保存新的账户数据
    [AccountModel save];
    // tableview删除对应账户的行
    [self deleteRowAtIndexPath:indexPath withRowAnimation:UITableViewRowAnimationAutomatic];
    // 发个广播，通知home界面更新ui
    [NSNotificationCenter.defaultCenter postNotificationName:KeePassAccountChangedNotificationName object:nil];
    //[self reloadData];
}
#pragma mark - setter
- (void)setAccounts:(NSMutableArray *)accounts {
    _accounts = accounts;
    [self reloadData];
}
#pragma mark - table view data source
- (NSInteger)tableView:(UITableView *)tableView numberOfRowsInSection:(NSInteger)section {
    return _accounts.count;
}
- (UITableViewCell *)tableView:(UITableView *)tableView cellForRowAtIndexPath:(NSIndexPath *)indexPath {
    HomeTalkTableCell *cell = [self dequeueReusableCellWithIdentifier:homeCellReuseId];
    cell.account = _accounts[indexPath.row];
    UITapGestureRecognizer *tapGesture = [[UITapGestureRecognizer alloc] initWithTarget:self action:@selector(editClick:)];
    tapGesture.numberOfTapsRequired = 1;
    [cell addGestureRecognizer:tapGesture];
    cell.userInteractionEnabled = YES;
    cell.backgroundColor = WHITE_COLOR;
    return cell;
}

