    static id accounts = nil;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        accounts = [NSArray arrayWithJsonFile:self.filePath elementClass:AccountModel.class];
    });
    return accounts;
}
- (NSDictionary *)dictionaryRepresentation {
    NSMutableDictionary *dict = [NSMutableDictionary dictionary];
    dict[@"ID"] = @(self.ID);
    dict[@"aiName"] = self.aiName;
//    dict[@"recentChat"] = self.recentChat;
//    dict[@"iconimage"] = UIImagePNGRepresentation(self.iconimage);

    return dict;
}

+ (void)save {
    [AccountModel.accounts writeToJsonFile:self.filePath];

    // 将 accounts 转换为 JSON 格式的字符串并打印
    NSError *error = nil;
    NSData *jsonData = [NSJSONSerialization dataWithJSONObject:[AccountModel.accounts valueForKey:@"dictionaryRepresentation"] options:NSJSONWritingPrettyPrinted error:&error];

    if (!error) {
        NSString *jsonString = [[NSString alloc] initWithData:jsonData encoding:NSUTF8StringEncoding];
        //NSLog(@"Accounts.json 内容:\n%@", jsonString);
    } else {
        NSLog(@"转换 JSON 失败: %@", error.localizedDescription);
    }
}

+ (void)deleteAllAccounts {
    NSLog(@"BeforedeleteAllAccounts，count=%ld", [AccountModel.accounts count]);
    NSMutableArray *accountsToDelete = [NSMutableArray array];

    for (AccountModel *deleteAccount in AccountModel.accounts) {
        NSInteger aiID = deleteAccount.ID;
        // 删除文件
        [MessageModel deleteMessagesFileForAccount:aiID];
        // 记录要删除的账号
        [accountsToDelete addObject:deleteAccount];
    }
    // 从 accounts 中删除记录的账号
    [AccountModel.accounts removeObjectsInArray:accountsToDelete];
    // 保存新的账户数据
    [AccountModel save];
    NSLog(@"AfterdeleteAllAccounts，count=%ld", [AccountModel.accounts count]);
}

